        if any(w in text for w in ['video', 'console', 'nintendo', 'sony', 'xbox', 'ps2', 'doom', 'quake', 'software']):
             scores['Sci/Tech'] += 2
        if any(w in text for w in ['team', 'coach', 'medal', 'olympic', 'stadium', 'ball']):
             scores['Sports'] += 2

    # Pick max
    return max(scores, key=scores.get)

